// Time:  O(n)
// Space: O(1)

class Solution {
public:
    string decodeAtIndex(string S, int K) {
        uint64_t n = 0;
        for (int i = 0; i < S.length(); ++i) {
            if (isdigit(S[i])) {
                n *= S[i] - '0';
            } else {
                ++n;
            }
        }

        for (int i = S.length() - 1; i >= 0; --i) {
            K %= n;
            if (K == 0 && isalpha(S[i])) {
                return (string) "" + S[i];
            }

            if (isdigit(S[i])) {
                n /= S[i] - '0';
            } else {
                --n;
            }
        }
    }
};

# Time:  O(n)
# Space: O(1)

class Solution(object):
    def decodeAtIndex(self, S, K):
        """
        :type S: str
        :type K: int
        :rtype: str
        """
        i = 0
        for c in S:
            if c.isdigit():
                i *= int(c)
            else:
                i += 1

        for c in reversed(S):
            K %= i
            if K == 0 and c.isalpha():
                return c

            if c.isdigit():
                i /= int(c)
            else:
                i -= 1
